class JwtService {
    private final Key signingKey;

    JwtService(Key signingKey) {
        this.signingKey = signingKey;
    }

    String generateToken(String subject, List<String> authorities) {
        Instant now = Instant.now();
        return Jwts.builder()
            .subject(subject)
            .claim("authorities", authorities)
            .issuedAt(Date.from(now))
            .expiration(Date.from(now.plus(15, ChronoUnit.MINUTES)))
            .signWith(signingKey)
            .compact();
    }

    boolean isTokenValid(String token, UserDetails userDetails) {
        Claims claims = Jwts.parser().verifyWith((SecretKey) signingKey).build()
            .parseSignedClaims(token).getPayload();

        String subject = claims.getSubject();
        Date exp = claims.getExpiration();
        return userDetails.getUsername().equals(subject) && exp.after(new Date());
    }
}
